mapper.select:
SELECT id, name, description, industry, size, city, address, logo_url AS logoUrl, audit_status AS auditStatus, created_at AS createdAt, job_count As jobCount, financing_stage As financingStage, official_web As officialWeb, phone
FROM companies WHERE 1=1
AND name LIKE CONCAT('%', #{keyword}, '%')
AND industry = #{industry}
AND size = #{companySize}
AND city = #{city}
AND audit_status = #{auditStatus}
ORDER BY created_at DESC

SELECT c.id, c.name, c.industry, c.size, c.city, c.address, c.audit_status AS auditStatus, c.phone, c.financing_stage AS financingStage, c.official_web AS officialWeb, c.description, c.logo_url AS logoUrl, c.license_url AS licenseUrl, c.audit_remark AS auditRemark, COALESCE(u.realname, u.nickname, '') AS registrant, DATE_FORMAT(c.created_at, '%Y-%m-%d %H:%i:%s') AS createdAt FROM companies c LEFT JOIN users u ON c.user_id = u.id WHERE 1=1
AND c.name LIKE CONCAT('%', #{name}, '%')
AND c.industry = #{industry}
AND c.audit_status = #{auditStatus}
ORDER BY c.created_at DESC
